{
  "$schema": "https://metaharness.dev/schemas/mcp-policy/v1",
  "defaultDeny": true,
  "comment": "Default-deny policy for @metaharness/example-twilio. All tools listed here are read-only or sandbox-safe. Any tool that sends a real message, makes a real call, or modifies account state is NOT listed and therefore blocked unless --allow-mutations is passed at harness startup.",
  "mutations_require_flag": "--allow-mutations",
  "allowNetwork": true,
  "allowNetworkHosts": ["api.twilio.com"],
  "allowShell": false,
  "allowFileWrite": false,
  "requireApprovalForDangerous": true,
  "toolTimeoutMs": 30000,
  "maxToolCallsPerTurn": 10,
  "auditLog": true,
  "auditLogPath": ".harness/audit/mcp-calls.jsonl",
  "grantedTools": [
    {
      "tool": "twilio.messages.list",
      "reason": "Read message history; no side-effects"
    },
    {
      "tool": "twilio.messages.fetch",
      "reason": "Fetch a single message by SID; no side-effects"
    },
    {
      "tool": "twilio.calls.list",
      "reason": "Read call log; no side-effects"
    },
    {
      "tool": "twilio.calls.fetch",
      "reason": "Fetch a single call record by SID; no side-effects"
    },
    {
      "tool": "twilio.accounts.fetch",
      "reason": "Read account metadata (status, friendly name); no side-effects"
    },
    {
      "tool": "twilio.availablePhoneNumbers.list",
      "reason": "Search available numbers; read-only, no purchase"
    },
    {
      "tool": "twilio.incomingPhoneNumbers.list",
      "reason": "List owned phone numbers; no side-effects"
    },
    {
      "tool": "twilio.lookups.phoneNumbers.fetch",
      "reason": "Look up carrier/line-type for a number; read-only"
    }
  ],
  "blockedTools": [
    {
      "tool": "twilio.messages.create",
      "reason": "Sends a real SMS/MMS — mutation; requires --allow-mutations"
    },
    {
      "tool": "twilio.calls.create",
      "reason": "Places a real phone call — mutation; requires --allow-mutations"
    },
    {
      "tool": "twilio.incomingPhoneNumbers.create",
      "reason": "Purchases a phone number (billing impact) — requires --allow-mutations"
    },
    {
      "tool": "twilio.incomingPhoneNumbers.update",
      "reason": "Modifies number configuration — requires --allow-mutations"
    },
    {
      "tool": "twilio.incomingPhoneNumbers.remove",
      "reason": "Releases a phone number — requires --allow-mutations"
    },
    {
      "tool": "twilio.calls.update",
      "reason": "Modifies or cancels an in-progress call — requires --allow-mutations"
    }
  ],
  "sandboxNote": "Set TWILIO_TEST_ACCOUNT_SID and TWILIO_TEST_AUTH_TOKEN to use Twilio's test credentials. Test-credential requests never touch real numbers or incur charges. See .env.example."
}
